mapper.update:
UPDATE TBL_VOLUN_APPLY
SET VOLUNACT_APPLYSTATUS = 9,
    VOLUNACT_ATTENDANCE = #{volunActAttendance}
WHERE VOLUN_ACT_NO = #{volunActNo}
  AND USER_NO = #{userNo}
  AND VOLUNACT_APPLYSTATUS = 1

mapper.select:
SELECT VOLUN_ACT_NO AS volunActNo, VOLUN_ACT_TITLE AS volunActTitle, VOLUN_ACT_ACT_TYPE AS volunActActType, DATE_FORMAT(VOLUN_ACT_RECRU_BEGIN, '%Y-%m-%d') AS volunActRecruBegin, DATE_FORMAT(VOLUN_ACT_RECRU_END, '%Y-%m-%d') AS volunActRecruEnd, CASE WHEN NOW() < VOLUN_ACT_RECRU_BEGIN THEN '모집예정' WHEN NOW() < DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY) THEN '모집중' ELSE '모집마감' END AS recruStatus FROM TBL_VOLUN_ACTIVITY WHERE VOLUN_ACT_ORGAN_NO = #{volunActOrganNo}
AND VOLUN_ACT_ACT_TYPE = #{actType}
AND ( (#{recruitStatus} = 'before-recruit' AND NOW() < VOLUN_ACT_RECRU_BEGIN) OR (#{recruitStatus} = 'recruit' AND NOW() >= VOLUN_ACT_RECRU_BEGIN AND NOW() < DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY)) OR (#{recruitStatus} = 'recruit-end' AND NOW() >= DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY)) )
AND VOLUN_ACT_TITLE LIKE CONCAT('%', #{keyword}, '%')
ORDER BY VOLUN_ACT_RECRU_END DESC

SELECT VOLUN_ACT_NO AS volunActNo, VOLUN_ACT_TITLE AS volunActTitle, VOLUN_ACT_ACT_TYPE AS volunActActType, DATE_FORMAT(VOLUN_ACT_RECRU_BEGIN, '%Y-%m-%d') AS volunActRecruBegin, DATE_FORMAT(VOLUN_ACT_RECRU_END, '%Y-%m-%d') AS volunActRecruEnd, DATE_FORMAT(VOLUN_ACT_PROC_BEGIN, '%Y-%m-%d') AS volunActProcBegin, DATE_FORMAT(VOLUN_ACT_PROC_END, '%Y-%m-%d') AS volunActProcEnd, CASE WHEN NOW() < VOLUN_ACT_RECRU_BEGIN THEN '모집예정' WHEN NOW() < DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY) THEN '모집중' ELSE '모집마감' END AS recruStatus FROM TBL_VOLUN_ACTIVITY WHERE VOLUN_ACT_ORGAN_NO = #{volunActOrganNo}
AND VOLUN_ACT_ACT_TYPE = #{actType}
AND ( (#{recruitStatus} = 'before-recruit' AND NOW() < VOLUN_ACT_RECRU_BEGIN) OR (#{recruitStatus} = 'recruit' AND NOW() >= VOLUN_ACT_RECRU_BEGIN AND NOW() < DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY)) OR (#{recruitStatus} = 'recruit-end' AND NOW() >= DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY)) )
AND VOLUN_ACT_TITLE LIKE CONCAT('%', #{keyword}, '%')
ORDER BY CASE WHEN CURDATE() < VOLUN_ACT_RECRU_BEGIN THEN 2 WHEN CURDATE() <= VOLUN_ACT_RECRU_END THEN 1 ELSE 3 END, CASE WHEN CURDATE() >= VOLUN_ACT_RECRU_BEGIN AND CURDATE() <= VOLUN_ACT_RECRU_END THEN VOLUN_ACT_RECRU_END WHEN CURDATE() < VOLUN_ACT_RECRU_BEGIN THEN VOLUN_ACT_RECRU_BEGIN END ASC, CASE WHEN CURDATE() > VOLUN_ACT_RECRU_END THEN VOLUN_ACT_RECRU_END END DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(VOLUN_ACT_NO) FROM TBL_VOLUN_ACTIVITY WHERE VOLUN_ACT_ORGAN_NO = #{volunActOrganNo}
AND VOLUN_ACT_ACT_TYPE = #{actType}
AND ( (#{recruitStatus} = 'before-recruit' AND NOW() < VOLUN_ACT_RECRU_BEGIN) OR (#{recruitStatus} = 'recruit' AND NOW() >= VOLUN_ACT_RECRU_BEGIN AND NOW() < DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY)) OR (#{recruitStatus} = 'recruit-end' AND NOW() >= DATE_ADD(VOLUN_ACT_RECRU_END, INTERVAL 1 DAY)) )
AND VOLUN_ACT_TITLE LIKE CONCAT('%', #{keyword}, '%')
